const hires = [
  {
    name: 'Sofia Park',
    role: 'Junior Frontend Engineer',
    manager: 'Alex Chen',
    start_date: '2026-06-30',
    week_in_role: 2,
    milestones: [
      { name: 'Complete IT setup (laptop, accounts, tools)', due_day: 1, completed: true, completed_date: '2026-06-30' },
      { name: 'Meet entire team (introductions done)', due_day: 3, completed: true, completed_date: '2026-07-02' },
      { name: 'Read product onboarding docs and codebase intro', due_day: 5, completed: true, completed_date: '2026-07-04' },
      { name: 'First PR submitted (however small)', due_day: 10, completed: true, completed_date: '2026-07-09' },
      { name: 'Complete first independent task (PM-assigned)', due_day: 14, completed: false, completed_date: null },
      { name: '30-day check-in with manager', due_day: 30, completed: false, completed_date: null },
      { name: 'Ship first user-facing feature', due_day: 45, completed: false, completed_date: null }
    ],
    manager_notes: 'Sofia is integrating well. First PR merged independently. Gaining confidence quickly.',
    buddy: 'James Kim'
  }
];
const today = '2026-07-14';
return [{ json: { hires, today } }];

const { hires, today } = $input.first().json;
const todayMs = new Date(today).getTime();
const reports = hires.map(hire => {
  const startMs = new Date(hire.start_date).getTime();
  const days_in_role = Math.floor((todayMs - startMs) / (1000*60*60*24));
  const milestones_with_status = hire.milestones.map(m => {
    const due_date = new Date(startMs + m.due_day * 24*60*60*1000);
    const overdue = !m.completed && todayMs > due_date.getTime();
    const days_overdue = overdue ? Math.floor((todayMs - due_date.getTime())/(1000*60*60*24)) : 0;
    return { ...m, due_date: due_date.toISOString().slice(0,10), overdue, days_overdue };
  });
  const completed = milestones_with_status.filter(m => m.completed).length;
  const total = milestones_with_status.length;
  const overdue_items = milestones_with_status.filter(m => m.overdue);
  const next_due = milestones_with_status.filter(m => !m.completed && !m.overdue).sort((a,b)=>a.due_day-b.due_day)[0];
  return { name: hire.name, role: hire.role, manager: hire.manager, start_date: hire.start_date, days_in_role, week_in_role: hire.week_in_role, milestones: milestones_with_status, completed, total, pct_complete: parseFloat(((completed/total)*100).toFixed(0)), overdue_items, next_due, manager_notes: hire.manager_notes, buddy: hire.buddy };
});
const total_overdue = reports.reduce((s,r) => s + r.overdue_items.length, 0);
return [{ json: { reports, today, meta: { hire_count: reports.length, total_overdue } } }];

const { reports, today, meta: m } = $input.first().json;
const hireLines = reports.map(r => {
  const mLines = r.milestones.map(ms => `    [${ms.completed?'✓':'○'}${ms.overdue?' ⚠️ OVERDUE '+ms.days_overdue+'d':''}] Day ${ms.due_day}: ${ms.name}${ms.completed?' (done '+ms.completed_date+')':' (due '+ms.due_date+')'}`).join('\n');
  return [
    `  ${r.name} — ${r.role} | Day ${r.days_in_role} | ${r.pct_complete}% complete`,
    `  Manager: ${r.manager} | Buddy: ${r.buddy}`,
    r.overdue_items.length > 0 ? `  ⚠️ ${r.overdue_items.length} OVERDUE milestone(s)` : '  ✅ On track',
    r.next_due ? `  Next due: Day ${r.next_due.due_day} — ${r.next_due.name}` : '',
    `  Manager notes: ${r.manager_notes}`,
    `  MILESTONES:`,
    mLines
  ].filter(Boolean).join('\n');
}).join('\n\n');
const report = [
  `NEW HIRE ONBOARDING TRACKER`,
  `As of: ${today} | ${m.hire_count} active hire(s) | ${m.total_overdue} overdue milestone(s)`,
  ``,
  hireLines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
